#!/usr/bin/env bun
/**
 * musiccard/index.ts — Download a YouTube audio sample and scaffold a music card
 *
 * Dual-mode: CLI (`bun src/tools/musiccard/index.ts <url>`) or native tool via registry.
 *
 * Pipeline: metadata → extract → analyze → card → refine
 *
 * Usage:
 *   bun src/tools/musiccard/index.ts <youtube-url>
 *   bun src/tools/musiccard/index.ts <youtube-url> --slug my-track-name
 *   bun src/tools/musiccard/index.ts <youtube-url> --start 300 --duration 300
 *   bun src/tools/musiccard/index.ts <youtube-url> --type music-video
 *   bun src/tools/musiccard/index.ts <youtube-url> --no-analyze
 */

import { existsSync, writeFileSync } from "fs";
import { join } from "path";
import { z } from "zod";
import dayjs from "../../libs/dayjs.js";
import { fromRoot } from "../../libs/paths.js";
import type { ToolDefinition } from "../../registry/types.js";

import { analyzeFromMetadata, type YtMeta } from "./profiles.js";
import { fetchMetadata, downloadAndTrim } from "./extract.js";
import { analyzeAudio } from "./analyze.js";
import { buildCard } from "./card.js";
import { refineWithGemini } from "./refine.js";

// ── Types ──────────────────────────────────────────────────────────────────

const VALID_TYPES = ["background-mix", "music-video", "single-track", "live-performance"] as const;
type CardType = (typeof VALID_TYPES)[number];

interface MusicCardArgs {
  url: string;
  title?: string;
  slug?: string;
  start?: number;
  duration?: number;
  type?: string;
  genre?: string;
  mood?: string;
  skipAnalyze?: boolean;
}

// ── Helpers ────────────────────────────────────────────────────────────────

function formatTime(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${String(s).padStart(2, "0")}`;
}

function formatDuration(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return s > 0 ? `${m}m${String(s).padStart(2, "0")}s` : `${m}m00s`;
}

// ── Core pipeline ──────────────────────────────────────────────────────────

async function createMusicCard(args: MusicCardArgs): Promise<string> {
  const cardsDir = fromRoot("vault", "studio", "references", "shared", "music-cards");
  const audioDir = join(cardsDir, "audio");
  const cardType = (args.type || "background-mix") as CardType;
  let startSec = args.start ?? 300;
  let duration = args.duration ?? 300;

  const out: string[] = [];

  // 1. Fetch metadata
  out.push("Fetching metadata...");
  const meta = fetchMetadata(args.url);
  if (args.title) meta.title = args.title;
  out.push(`  Title: ${meta.title}`);
  out.push(`  Channel: ${meta.channel}`);
  out.push(`  Duration: ${Math.floor(meta.duration / 60)}m${meta.duration % 60}s`);

  // 2. Derive slug
  let slug = args.slug || "";
  if (!slug) {
    slug = meta.title
      .toLowerCase()
      .replace(/[^\w\s-]/g, "")
      .replace(/\s+/g, "-")
      .replace(/-+/g, "-")
      .replace(/^-|-$/g, "");
    if (slug.length > 32) {
      slug = slug.slice(0, 32).replace(/-[^-]*$/, "");
    }
  }

  const baseSlug = slug; // stable key for download caching
  const datePrefix = dayjs().format("YYYY-MM-DD-HHmmss");
  const cardSlug = `${datePrefix}-${slug}`;
  const audioSlug = `${datePrefix}-${slug}`;

  if (existsSync(join(cardsDir, `${cardSlug}.md`))) {
    throw new Error(`Card already exists: ${cardSlug}.md — use --slug to specify a different name.`);
  }

  out.push(`  Card slug: ${cardSlug}`);
  out.push(`  Audio slug: ${audioSlug}`);

  // 3. Clamp sample window
  if (startSec + duration > meta.duration) {
    if (meta.duration <= duration) {
      startSec = 0;
      duration = meta.duration;
      out.push(`  Source shorter than sample — extracting full audio (${formatDuration(duration)})`);
    } else {
      startSec = Math.max(0, meta.duration - duration);
      out.push(`  Adjusted start to ${startSec}s to fit within source`);
    }
  }

  // 4. Download + trim
  out.push("Downloading audio...");
  const extract = downloadAndTrim(args.url, audioDir, audioSlug, startSec, duration, baseSlug);
  out.push(`  Audio: ${audioSlug}.mp3 (${extract.fileSizeMB}MB, ${formatTime(extract.actualDuration)})`);

  // 5. Audio analysis
  let audioAnalysis = null;
  if (!args.skipAnalyze) {
    out.push("Analyzing audio...");
    audioAnalysis = analyzeAudio(extract.audioFile);
    if (audioAnalysis) {
      out.push(`  BPM: ${audioAnalysis.bpm} | Key: ${audioAnalysis.key.label} | Energy: ${audioAnalysis.energy.level} | Brightness: ${audioAnalysis.spectral.brightness}`);
    } else {
      out.push("  Audio analysis unavailable — falling back to metadata-only profile");
    }
  }

  // 6. Build profile + card
  out.push("Building profile from metadata...");
  const profile = analyzeFromMetadata(meta);
  const sampleLabel = `${formatTime(startSec)}–${formatTime(startSec + extract.actualDuration)}`;
  const durationLabel = formatDuration(extract.actualDuration);
  const today = dayjs().format("YYYY-MM-DD");

  const cardContent = buildCard({
    meta, profile, audioAnalysis, audioSlug, cardType,
    sampleLabel, durationLabel, sourceUrl: args.url, today,
  });

  const cardFile = join(cardsDir, `${cardSlug}.md`);
  writeFileSync(cardFile, cardContent, "utf-8");
  out.push(`  Card: ${cardSlug}.md`);

  // 7. Gemini refinement
  if (!args.skipAnalyze) {
    out.push("Refining with Gemini...");
    const refined = await refineWithGemini({ meta, cardType, cardContent, audioAnalysis, genre: args.genre, mood: args.mood });
    if (refined) {
      writeFileSync(cardFile, refined.refined, "utf-8");
      out.push("  Gemini refinement applied");
      if (refined.usage) out.push(`  Gemini: ${refined.usage}`);
    } else {
      out.push("  Gemini refinement skipped — keeping metadata-based version");
    }
  }

  // 8. Summary
  const ytTags = meta.tags.slice(0, 10).map(t => t.toLowerCase().replace(/\s+/g, "-"));
  out.push("");
  out.push("=== MUSIC CARD CREATED ===");
  out.push(JSON.stringify({
    slug: cardSlug, audioSlug, card: cardFile, audio: extract.audioFile,
    type: cardType, source: args.url, sample: sampleLabel,
    duration: durationLabel, title: meta.title, channel: meta.channel, tags: ytTags,
  }, null, 2));
  out.push("=== END ===");

  return out.join("\n");
}

// ── Tool definition ────────────────────────────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "musiccard",
  description: "Download a YouTube audio sample and scaffold an Obsidian music card with BPM/key analysis, genre profile, and Suno/MiniMax translations.",
  tags: ["creative", "reference"],
  inputSchema: z.object({
    url: z.string().describe("YouTube URL"),
    title: z.string().optional().describe("Override card title and slug (default: YouTube title)"),
    slug: z.string().optional().describe("Custom slug for filenames (default: derived from title)"),
    start: z.number().optional().describe("Sample start time in seconds (default: 300)"),
    duration: z.number().optional().describe("Sample length in seconds (default: 300)"),
    type: z.string().optional().describe("Card type: background-mix, music-video, single-track, live-performance"),
    genre: z.string().optional().describe("User-defined genre hint for Gemini refinement"),
    mood: z.string().optional().describe("User-defined mood hint for Gemini refinement"),
    skipAnalyze: z.boolean().optional().describe("Skip audio analysis and Gemini refinement"),
  }),
  execute: async (args) => {
    try {
      const output = await createMusicCard(args);
      return { output };
    } catch (err: any) {
      return { output: `[musiccard error] ${err.message}`, isError: true };
    }
  },
};

// ── CLI mode ───────────────────────────────────────────────────────────────

if (import.meta.main) {
  let url = "", title = "", slug = "", startSec = 300, duration = 300;
  let cardType: CardType = "background-mix";
  let genre = "", mood = "";
  let skipAnalyze = false;

  const cliArgs = process.argv.slice(2);
  for (let i = 0; i < cliArgs.length; i++) {
    const arg = cliArgs[i];
    if (arg === "--title") title = cliArgs[++i];
    else if (arg === "--slug") slug = cliArgs[++i];
    else if (arg === "--start") startSec = parseInt(cliArgs[++i]);
    else if (arg === "--duration") duration = parseInt(cliArgs[++i]);
    else if (arg === "--type") {
      const t = cliArgs[++i] as CardType;
      if (!VALID_TYPES.includes(t)) {
        console.error(`Invalid type "${t}". Must be one of: ${VALID_TYPES.join(", ")}`);
        process.exit(1);
      }
      cardType = t;
    }
    else if (arg === "--genre") genre = cliArgs[++i];
    else if (arg === "--mood") mood = cliArgs[++i];
    else if (arg === "--no-analyze") skipAnalyze = true;
    else if (arg.startsWith("http")) url = arg;
  }

  if (!url) {
    console.log("Usage: bun src/tools/musiccard/index.ts <youtube-url> [--slug name] [--start 300] [--duration 300] [--type background-mix]");
    process.exit(1);
  }

  try {
    const output = await createMusicCard({ url, title: title || undefined, slug, start: startSec, duration, type: cardType, genre: genre || undefined, mood: mood || undefined, skipAnalyze });
    console.log(output);
  } catch (err: any) {
    console.error(`[musiccard error] ${err.message}`);
    process.exit(1);
  }
}

/**
 * refine.ts — Gemini refinement pass for music cards
 *
 * Takes the generated card + metadata + audio analysis and asks Gemini
 * to improve mood descriptions, groove details, and translations.
 */

import { generateText } from "../../libs/gemini.js";
import type { YtMeta } from "./profiles.js";
import type { AudioAnalysis } from "./analyze.js";

export interface RefineInput {
  meta: YtMeta;
  cardType: string;
  cardContent: string;
  audioAnalysis: AudioAnalysis | null;
  genre?: string;
  mood?: string;
}

/**
 * Refine a music card via Gemini. Returns the improved card content,
 * or null if refinement fails (caller should keep the original).
 */
export async function refineWithGemini(input: RefineInput): Promise<{ refined: string; usage?: string } | null> {
  const { meta, cardType, cardContent, audioAnalysis, genre, mood } = input;

  const userContextSection = (genre || mood)
    ? `\nUser-provided context (use as strong hints for genre matching and translations):${genre ? `\n  Genre: ${genre}` : ""}${mood ? `\n  Mood: ${mood}` : ""}\n`
    : "";

  const audioDataSection = audioAnalysis
    ? `\nAudio analysis (from librosa — these are measured values, trust them):
  BPM: ${audioAnalysis.bpm}
  Key: ${audioAnalysis.key.label} (confidence: ${audioAnalysis.key.confidence})
  Energy: ${audioAnalysis.energy.level} (RMS: ${audioAnalysis.energy.rms}, dynamics: ${audioAnalysis.energy.dynamics})
  Spectral: brightness=${audioAnalysis.spectral.brightness}, width=${audioAnalysis.spectral.width} (centroid: ${audioAnalysis.spectral.centroid}Hz)
  Rhythm density: ${audioAnalysis.rhythm.density} (${audioAnalysis.rhythm.onsetsPerSec} onsets/sec)\n`
    : "";

  const prompt = `You are a music production analyst. Given this music card with values derived from YouTube metadata and audio analysis, refine and improve the analysis based on your knowledge of the genre(s).

Title: ${meta.title}
Channel: ${meta.channel}
Tags: ${meta.tags.join(", ")}
Description: ${meta.description}
Card type: ${cardType}
${userContextSection}${audioDataSection}
Current card content:
${cardContent}

Return ONLY the updated card content (everything between and including the --- frontmatter delimiters). Keep the same structure. The BPM and Key values from audio analysis are measured — keep them accurate (don't replace with ranges). Improve mood descriptions, groove details, palette instruments, and translations based on genre knowledge and the audio data. Make the Suno translation a comma-separated list of style tags. Make the MiniMax translation a natural-language prompt. Do not add new sections. Do not remove any sections. Do not change the Audio embed line.`;

  try {
    const result = await generateText(prompt, {
      model: "gemini-2.5-flash",
      timeout: 90_000,
      temperature: 0.4,
      caller: "musiccard",
    });

    const fmMatch = result.text.match(/^---\n[\s\S]*?\n---[\s\S]*/m);
    if (!fmMatch) return null;

    const usage = (result.inputTokens || result.outputTokens)
      ? `${result.inputTokens ?? "?"} in / ${result.outputTokens ?? "?"} out tokens`
      : undefined;

    return { refined: fmMatch[0].trim() + "\n", usage };
  } catch {
    return null;
  }
}

#!/usr/bin/env bun
/**
 * suno-meta.ts — CLI entry point and tool registry export.
 *
 * Core API logic lives in src/libs/suno-api/index.ts.
 * This file handles CLI argument parsing, output formatting, and toolDef export.
 *
 * Usage:
 *   bun run tool suno-meta <path.mp3> [--json]
 *   bun run tool suno-meta --check-token
 *   bun run tool suno-meta --setup-help
 *   bun run tool suno-meta --help
 */

import { z } from "zod";
import type { ToolDefinition } from "../registry/types.js";
import {
  extractMeta,
  SunoError,
  sunoHeaders,
  BASE,
  type SunoExtractResult,
} from "../libs/suno-api/index.js";

// Re-export for test imports
export { extractMeta, SunoError } from "../libs/suno-api/index.js";
export type { SunoExtractResult } from "../libs/suno-api/index.js";

// ── Output formatters ──────────────────────────────────────────────────────────

function prettyOutput(result: SunoExtractResult): string {
  const line = "──────────────────────────────────────";
  const sectionLine = (label: string): string =>
    `─── ${label} ${"─".repeat(Math.max(0, 38 - label.length))}`;
  return [
    `Suno extraction — ${result.file.filename}`,
    line,
    "",
    `Duration:     ${result.duration_seconds}s`,
    `Has vocal:    ${result.has_vocal ? "yes" : "no"}`,
    `Display tags: ${result.display_tags}`,
    `Audio URL:    ${result.audio_url}`,
    "",
    sectionLine("Style (prose)"),
    "",
    result.style_prose,
    "",
    sectionLine("Lyrics"),
    "",
    result.lyrics,
    "",
    sectionLine("Raw IDs"),
    `Upload ID: ${result.upload_id}`,
    `Clip ID:   ${result.clip_id}`,
  ].join("\n");
}

// ── --check-token ──────────────────────────────────────────────────────────────

async function checkToken(): Promise<{ message: string; exitCode: number }> {
  if (!process.env.SUNO_AUTHORIZATION) {
    return {
      message:
        "SUNO_AUTHORIZATION is not set. Run 'suno-meta --setup-help' for extraction instructions.",
      exitCode: 1,
    };
  }
  if (!process.env.SUNO_BROWSER_TOKEN) {
    return {
      message:
        "SUNO_BROWSER_TOKEN is not set. Run 'suno-meta --setup-help' for extraction instructions.",
      exitCode: 1,
    };
  }
  if (!process.env.SUNO_DEVICE_ID) {
    return {
      message:
        "SUNO_DEVICE_ID is not set. Run 'suno-meta --setup-help' for extraction instructions.",
      exitCode: 1,
    };
  }

  // Use /api/billing/info/ — a GET-supported, authenticated endpoint that
  // returns user subscription metadata. Chosen as a cheap auth probe because
  // it has zero side effects and clearly distinguishes 200 (valid) from 401
  // (expired). The previous /api/uploads/audio/ choice was POST-only and
  // returned 405 regardless of auth state.
  try {
    const res = await fetch(`${BASE}/api/billing/info/`, {
      method: "GET",
      headers: sunoHeaders(),
    });
    if (res.status === 200) {
      return { message: "Token valid", exitCode: 0 };
    }
    if (res.status === 401) {
      return {
        message:
          "Suno rejected auth. Token may be expired. Run 'suno-meta --setup-help' to refresh.",
        exitCode: 2,
      };
    }
    return {
      message: `Unexpected status from Suno token check: ${res.status}.`,
      exitCode: 3,
    };
  } catch (err: any) {
    return {
      message: `Unexpected error during token check: ${err?.message ?? err}. If this reproduces, capture HAR and open an issue.`,
      exitCode: 99,
    };
  }
}

// ── --setup-help ───────────────────────────────────────────────────────────────

const SETUP_HELP = `\
suno-meta — setup instructions
═══════════════════════════════════════

This tool requires THREE values from an active Suno browser session:
  SUNO_AUTHORIZATION — your Bearer JWT (the primary auth)
  SUNO_BROWSER_TOKEN — a secondary JSON token Suno sends alongside
  SUNO_DEVICE_ID     — your device identifier (UUID)

Steps to extract them from Chrome DevTools:

  1. Open https://suno.com in Chrome and log in.
  2. Press F12 to open DevTools. Go to the Network tab.
  3. Reload the page and wait for requests to load.
  4. In the filter bar, type "studio-api" to filter Suno API requests.
  5. Click any request to studio-api-prod.suno.com.
  6. Go to the "Headers" tab → "Request Headers".
  7. Copy the value of "authorization" → this is SUNO_AUTHORIZATION.
     (Usually starts with "Bearer eyJ...". Include "Bearer " or not — the
     tool will handle either format.)
  8. Copy the value of "browser-token" → this is SUNO_BROWSER_TOKEN.
     (Looks like JSON: starts with { and ends with })
  9. Copy the value of "device-id" → this is SUNO_DEVICE_ID.
     (Looks like a UUID: 36 chars with dashes)
  10. Write them to .env (NOT .env.example — that's checked in) at the
      repo root:

     SUNO_AUTHORIZATION="Bearer eyJ..."
     SUNO_BROWSER_TOKEN="{\\"...\\":\\"...\\"}"
     SUNO_DEVICE_ID="12345678-1234-1234-1234-123456789012"

     (Wrap JSON values in double quotes so Bun's dotenv loader parses them
     cleanly. Escape inner double quotes with backslashes.)

  11. Verify with: bun run tool suno-meta --check-token

Notes:
  - Tokens expire periodically. If --check-token returns "expired",
    refresh by repeating steps 1-10.
  - Never share or commit these values. They authenticate as you on Suno.
  - .env is gitignored via the .env.* pattern — safe to use.
  - The HAR export from DevTools (File > Save all as HAR) also contains
    these values if you prefer to grep from a file.
`;

// ── --help ─────────────────────────────────────────────────────────────────────

const USAGE = `\
Usage: bun run tool suno-meta <path.mp3> [--json]
       bun run tool suno-meta --check-token
       bun run tool suno-meta --setup-help
       bun run tool suno-meta --help

Arguments:
  <path.mp3>        Path to a local mp3 file to upload and analyze.

Flags:
  --json            Output SunoExtractResult as JSON instead of pretty text.
  --check-token     Verify Suno auth is valid without uploading.
  --setup-help      Print instructions for extracting tokens from Chrome DevTools.
  --help            Print this usage message.

Environment:
  SUNO_AUTHORIZATION    Required. Bearer JWT (with or without "Bearer " prefix).
  SUNO_BROWSER_TOKEN    Required. Suno's secondary JSON token.
  SUNO_DEVICE_ID        Required. Your Suno device identifier (UUID).

Exit codes:
  0   Success
  1   Input validation error (missing token, file not found, non-mp3)
  2   Auth rejected (401 from Suno)
  3   Suno 4xx non-auth error
  4   Suno 5xx error
  5   S3 upload failed after 3 retries
  6   Analysis polling timeout or terminal failure status
  7   Unexpected response shape from Suno (missing expected fields)
  99  Unexpected error
`;

// ── Tool definition (registry autodiscovery) ───────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "suno-meta",
  description:
    "Upload a local mp3 to Suno's upload-audio endpoint and extract Suno's own Lyrics (typed-bracket) " +
    "and Style (rich prose) interpretation of the track. Requires SUNO_BROWSER_TOKEN and SUNO_DEVICE_ID env vars.",
  inputSchema: z.object({
    filePath: z.string().describe("Absolute or relative path to the local mp3 file to upload."),
    json: z.boolean().optional().describe("If true, output as JSON instead of pretty text."),
  }),
  tags: ["suno", "music-cards", "extraction"],
  execute: async (args) => {
    try {
      const result = await extractMeta(args.filePath);
      if (args.json) {
        return { output: JSON.stringify(result, null, 2) };
      }
      return { output: prettyOutput(result) };
    } catch (err: any) {
      const message = err?.message ?? String(err);
      return { output: message, isError: true };
    }
  },
};

// ── CLI entry point ────────────────────────────────────────────────────────────

if (import.meta.main) {
  const args = process.argv.slice(2);

  if (args.includes("--help") || args.length === 0) {
    process.stdout.write(USAGE);
    process.exit(0);
  }

  if (args.includes("--setup-help")) {
    process.stdout.write(SETUP_HELP);
    process.exit(0);
  }

  if (args.includes("--check-token")) {
    const { message, exitCode } = await checkToken();
    if (exitCode === 0) {
      process.stdout.write(message + "\n");
    } else {
      process.stderr.write(message + "\n");
    }
    process.exit(exitCode);
  }

  // Normal extraction mode
  const jsonFlag = args.includes("--json");
  const filePath = args.find(a => !a.startsWith("--")) ?? "";

  if (!filePath) {
    process.stderr.write("Error: no mp3 path provided.\n" + USAGE);
    process.exit(1);
  }

  try {
    const result = await extractMeta(filePath);
    if (jsonFlag) {
      process.stdout.write(JSON.stringify(result, null, 2) + "\n");
    } else {
      process.stdout.write(prettyOutput(result) + "\n");
    }
    process.exit(0);
  } catch (err: any) {
    const exitCode = err instanceof SunoError ? err.exitCode : 99;
    const message = err?.message ?? String(err);
    if (exitCode === 99 && !(err instanceof SunoError)) {
      process.stderr.write(
        `Unexpected error: ${message}. If this reproduces, capture HAR and open an issue.\n`
      );
    } else {
      process.stderr.write(message + "\n");
    }
    process.exit(exitCode);
  }
}

/**
 * suno-api/index.ts — Core Suno upload-and-analyze API client
 *
 * Implements the 7-step flow reverse-engineered from the Suno HAR capture:
 *   [1] POST /api/uploads/audio/              → upload session
 *   [2] POST <s3_url> (multipart, no auth)    → 204 (3x retry w/ backoff)
 *   [3] POST /api/uploads/audio/{id}/upload-finish/
 *   [4] GET  /api/uploads/audio/{id}/         → poll until complete (90s)
 *   [5] POST /api/uploads/audio/{id}/initialize-clip/  → clip_id (NEW id, not upload_id)
 *   [6] POST /api/gen/{clip_id}/set_metadata/ → lyrics in `prompt` field
 *   [7] POST /api/gen/{clip_id}/set_audio_description  → style in `metadata.tags`
 *
 * Auth: SUNO_BROWSER_TOKEN + SUNO_DEVICE_ID (never logged — values never touch stdout/stderr).
 *
 * Imported only by suno-meta.ts. Do not import from other tools or skills.
 */

import { existsSync } from "fs";
import { basename, extname } from "path";

// ── Constants ──────────────────────────────────────────────────────────────────

export const BASE = "https://studio-api-prod.suno.com";

// Step 6 — TRAILING SLASH mandatory. Django REST Framework (DRF) returns 301
// redirect without it, and fetch may lose the POST body on redirect.
export const URL_SET_METADATA = (clipId: string): string =>
  `${BASE}/api/gen/${clipId}/set_metadata/`; // trailing slash — DRF requires it

// Step 7 — NO trailing slash. DRF 404s if you add one here.
// This asymmetry is real and load-bearing — do not template these together.
export const URL_SET_AUDIO_DESCRIPTION = (clipId: string): string =>
  `${BASE}/api/gen/${clipId}/set_audio_description`; // NO trailing slash — DRF 404s with it

// Polling config — intentionally slower than the HAR-observed browser
// interval (~4000ms) to stay well under any rate-limit threshold.
export const POLL_INTERVAL_MS = 5000;
export const POLL_TIMEOUT_MS = 180_000; // 3 min — matches slower poll interval

// S3 retry config (step 2 only — no other retries per spec A5)
export const S3_MAX_RETRIES = 3;
export const S3_BACKOFF_MS = [1000, 2000, 4000] as const;

// Inter-step pacing — intentionally ≥1.5× the HAR-observed browser intervals.
// Derived from analysis of a real user session on 2026-04-09 (see ADR in
// suno-meta task doc). Goal: never look faster than a real browser.
// All values are "wait BEFORE calling the named step".
export const PACING = {
  afterStep1_beforeS3: 1_500,        // HAR: 430ms
  afterStep2_beforeUploadFinish: 3_000, // HAR: 1874ms — let S3 commit
  afterStep3_beforeFirstPoll: 1_500, // HAR: 503ms
